noncompliant:
class MyClass {
    int;  // Noncompliant - empty declaration
    ;     // Noncompliant - empty statement
    static;  // Noncompliant - empty static declaration
};

compliant:
class MyClass {
    int value;  // Compliant - proper member declaration
    static const int constant = 42;  // Compliant - proper static declaration

    void method();  // Compliant - proper method declaration
};
